const sources = {
  openai: { provider: 'openai', source_name: 'OpenAI Models', url: 'https://platform.openai.com/docs/models', patterns: ['GPT-5(?:\\.\\d+)?(?:\\s(?:mini|nano|pro|codex))?', 'o\\d(?:-pro)?'] },
  anthropic: { provider: 'anthropic', source_name: 'Anthropic Models', url: 'https://platform.claude.com/docs/en/docs/models-overview', patterns: ['Claude\\s(?:Opus|Sonnet|Haiku)\\s\\d(?:\\.\\d+)?'] },
  google: { provider: 'google', source_name: 'Google Gemini Models', url: 'https://ai.google.dev/gemini-api/docs/models/gemini', patterns: ['Gemini\\s\\d\\.\\d\\s(?:Flash|Pro|Ultra|TTS)', 'gemini-\\d\\.\\d-[a-z0-9\\-]+'] },
};

function normalize(text) {
  return String(text || '').replace(/\s+/g, ' ').trim();
}

function stripTags(value) {
  return normalize(String(value || '').replace(/<[^>]+>/g, ' ').replace(/&amp;/g, '&').replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, ' '));
}

function slugify(value) {
  return String(value || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '');
}

function yamlString(value) {
  const safe = String(value || '').replace(/\\/g, '\\\\').replace(/"/g, '\\"');
  return '"' + safe + '"';
}

const outputs = [];
for (const item of $input.all()) {
  const providerKey = item.json.provider;
  const source = sources[providerKey];
  if (!source) continue;
  const html = item.json.body || item.json.data || item.json.html || item.json.response || JSON.stringify(item.json);
  const text = stripTags(html);
  const models = [];
  for (const patternText of source.patterns) {
    const pattern = new RegExp(patternText, 'ig');
    for (const match of text.matchAll(pattern)) {
      const model = normalize(match[0]);
      if (model && !models.includes(model)) models.push(model);
    }
  }
  const latest = models.slice(0, 8);
  const now = new Date().toISOString();
  const datePart = now.slice(0, 10);
  const providerLabel = source.provider.charAt(0).toUpperCase() + source.provider.slice(1);
  const title = 'Latest ' + providerLabel + ' models snapshot';
  const fileName = datePart + '-' + slugify(source.provider) + '-latest-models-snapshot.md';
  const outputPath = '/vault/raw/passive/model/' + fileName;
  const excerpt = normalize(text.slice(0, 1200)) || 'Aucun extrait disponible.';
  const markdown = [
    '---',
    'kind: passive-capture',
    'source_name: ' + yamlString(source.source_name),
    'source_type: primaire',
    'category: model-snapshot',
    'provider: ' + source.provider,
    'signal_type: model-snapshot',
    'tags: [ia, ' + source.provider + ', model-snapshot]',
    'title: ' + yamlString(title),
    'url: ' + yamlString(source.url),
    'published_at: ' + yamlString(now),
    'collected_at: ' + yamlString(now),
    'confidence: high',
    'major_update: true',
    'workflow: manual-provider-models-snapshot',
    'status: a-traiter',
    '---',
    '',
    '# ' + title,
    '',
    '## Metadonnees',
    '- Provider : ' + source.provider,
    '- Source : ' + source.source_name,
    '- Type : primaire',
    '- Categorie : model-snapshot',
    '- URL : ' + source.url,
    '- Collecte le : ' + now,
    '',
    '## Modeles detectes',
    ...(latest.length ? latest.map((m) => '- ' + m) : ['- Aucun modele detecte automatiquement.']),
    '',
    '## Extrait brut',
    excerpt,
    '',
    '## Resume IA preliminaire',
    '- Snapshot manuel des derniers modeles visibles pour ' + source.provider + '.',
    '- Cette capture sert surtout a peupler raw/passive/model/ pour la veille provider.',
    '',
    '## Points a verifier',
    '- Verifier si ces modeles sont bien les plus recents visibles dans la documentation officielle.',
    '- Decider si une note provider doit etre creee ou mise a jour.',
    '',
    '## Action possible',
    '- [ ] Decider si cette entree merite une mise a jour dans wiki/notes/' + source.provider + '.md ou wiki/notes/modeles-ia.md',
    ''
  ].join('\n');
  outputs.push({ json: { provider: source.provider, source_name: source.source_name, title, outputPath, markdown } });
}
return outputs;
